/**
 * @fileoverview Combobox component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, spell patterns, SVG icons, defaults
 *   helpers.js   — parseNativeOptions, normalizeRemoteData, readInitialValue
 *   state.js     — reactive state creation
 *   view.js      — DOM setup, effects, rendering, positioning, darkroom
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/Combobox
 */

import { default as razyui } from '../../index.js';

import { CLS, DEFAULTS }                                    from './constants.js';
import { parseNativeOptions, normalizeRemoteData,
         readInitialValue }                                  from './helpers.js';
import { createReactiveState }                               from './state.js';
import { buildDOM, wireEffects, syncSelectionState,
         syncCheckboxState, openDarkroom, closeDarkroom,
         filterOptionItems }                                 from './view.js';
import { bindEvents, bindDarkroomClose }                       from './events.js';
import { attachOutsideClick }                                   from '../shared/outsideClick.js';
import { emitEvent }                                            from '../shared/emitEvent.js';

/**
 * Combobox — v2 modular rewrite
 *
 * Progressive enhancement of native <select> elements.
 * Replaces native rendering with a styled container + floating dropdown.
 * Reactive state via razyui.state(); property setters on getControl().
 *
 * Features:
 *   - Single and multiple selection
 *   - Optgroup support
 *   - Remote data loading via razyui.ajax()
 *   - Callbacks: onSelect, onDrawLabel
 *   - States: disabled, readonly, placeholder
 *   - Setter API: ctrl.value, ctrl.options, ctrl.disabled, ctrl.readonly
 */
const Combobox = class {
    #select = null;      // native <select> razyui wrapper
    #container = null;   // .combobox-container razyui wrapper
    #label = null;       // .combobox-label razyui wrapper
    #acInput = null;     // .combobox-input razyui wrapper (autocomplete mode)
    #floating = null;    // .combobox-floating razyui wrapper
    #optionsList = null; // .combobox-options razyui wrapper
    #config = {};
    #stateRef = null;    // razyui.state() stateRef
    #setState = null;    // razyui.state() setState
    #outsideAC = null; // for outside-click cleanup
    #destroyed = false;
    #eventAC = null;        // for static event cleanup
    #overlay = null;         // darkroom: fullscreen overlay
    #darkroomBody = null;    // darkroom: scrollable options list

    /** Emit a prefixed rui-* event from the native <select>. */
    #emit(name, detail = {}) {
        if (this.#select?.[0]) emitEvent(this.#select[0], name, detail);
    }

    /**
     * Creates a new Combobox instance.
     * @param {string|Element} selector - CSS selector or Element for the native <select>.
     * @param {Object} [config={}] - Configuration options.
     * @param {string} [config.url] - Remote JSON endpoint.
     * @param {boolean} [config.isKeyValuePair] - If true, remote data is {value: label}.
     * @param {string} [config.placeholder] - Placeholder text when nothing selected.
     * @param {Function} [config.onSelect] - Callback triggered on selection.
     * @param {Function} [config.onDrawLabel] - Callback to customize label rendering.
     * @param {Function} [config.onRenderOption] - Callback to customize dropdown item rendering.
     * @param {Function} [config.onRenderDarkroom] - Callback to customize darkroom panel item rendering.
     * @param {string} [config.display] - 'darkroom' (expand button + fullscreen overlay panel).
     * @param {boolean} [config.autocomplete] - Inline text input mode with type-to-filter.
     */
    constructor(selector, config = {}) {
        this.#config = config;
        this.#config.dropdownGap = razyui.JIT.TOKEN.spacePx(config.dropdownGap ?? DEFAULTS.dropdownGap);

        // Resolve the native <select>
        let selectWrapper = razyui(selector);

        // If the resolved element isn't a <select>, look for one inside it
        // (handles Custom Element wrappers like <rui-combobox> > <select>)
        if (selectWrapper.length && !selectWrapper.is('select')) {
            const inner = selectWrapper.find('select')[0];
            if (inner) {
                selectWrapper = razyui(inner);
            }
        }

        if (!selectWrapper.length || !selectWrapper.is('select')) {
            console.warn('Combobox: <select> element not found \u2192', selector);
            return;
        }

        this.#select = selectWrapper;
        const selectEl = selectWrapper[0];
        if (config.name) selectEl.name = config.name;
        const isMultiple = selectEl.type === 'select-multiple';

        // ── Build DOM ──
        const domRefs = buildDOM(razyui, this.#config, selectEl);
        this.#container = domRefs.container;
        this.#label = domRefs.label;
        this.#acInput = domRefs.acInput;
        this.#floating = domRefs.floating;
        this.#optionsList = domRefs.optionsList;

        // ── Reactive state ──
        const stateSet = createReactiveState(razyui.state, selectEl, this.#config);
        const [stateRef, setState] = stateSet;
        this.#stateRef = stateRef;
        this.#setState = setState;

        // ── Wire effects ──
        wireEffects(stateSet, {
            container: this.#container,
            label: this.#label,
            acInput: this.#acInput,
            floating: this.#floating,
            optionsList: this.#optionsList,
        }, this.#config, selectEl);

        // ── Event listeners ──
        const self = this;
        this.#eventAC = bindEvents({
            container: this.#container[0],
            optionsList: this.#optionsList[0],
            expandBtn: domRefs.expandBtn,
        }, {
            onContainerClick: () => {
                if (stateRef.disabled || stateRef.readonly) return;

                // Autocomplete mode: always open + focus the input (never toggle-close)
                if (config.autocomplete && self.#acInput && self.#acInput.length) {
                    if (!stateRef.open) {
                        setState({ open: true });
                        self.#attachOutsideClick();
                        self.#emit('open');
                    }
                    self.#acInput[0].focus();
                    return;
                }

                const willOpen = !stateRef.open;
                setState({ open: willOpen });
                if (willOpen) {
                    self.#attachOutsideClick();
                    self.#emit('open');
                } else {
                    self.#detachOutsideClick();
                    self.#emit('close');
                }
            },
            onOptionClick: (e) => {
                // In checkbox mode, checkbox clicks are handled by onCheckboxClick
                if (config.checkbox && e.target.closest('.' + CLS.CHECKBOX)) return;

                const item = e.target.closest('.' + CLS.ITEM);
                if (!item || razyui(item).hasClass(CLS.DISABLED)) return;
                e.stopPropagation();

                const val = item.dataset.value;
                if (isMultiple) {
                    const current = Array.isArray(stateRef.value) ? [...stateRef.value] : [];
                    const idx = current.indexOf(val);
                    if (idx >= 0) {
                        current.splice(idx, 1);
                    } else {
                        current.push(val);
                    }
                    setState({ value: current });
                } else {
                    setState({ value: val, open: false });
                    self.#detachOutsideClick();
                }

                // In checkbox mode, sync the checked state to match selection
                if (config.checkbox) {
                    const checked = stateRef.checked ? { ...stateRef.checked } : {};
                    if (isMultiple) {
                        // Mirror selection array to checked map
                        for (const o of stateRef.options) {
                            checked[o.value] = stateRef.value.includes(o.value);
                        }
                    } else {
                        for (const o of stateRef.options) {
                            checked[o.value] = o.value === val;
                        }
                    }
                    setState({ checked });
                    syncCheckboxState(self.#optionsList[0], stateRef);
                }

                if (typeof config.onSelect === 'function') {
                    config.onSelect.call(self, isMultiple ? stateRef.value : val);
                }
                const emitVal = isMultiple ? stateRef.value : val;
                self.#emit('select', { value: emitVal });
                self.#emit('change', { value: emitVal });
                if (!isMultiple) self.#emit('close');
            },
            onCheckboxClick: config.checkbox ? (e) => {
                const cbEl = e.target.closest('.' + CLS.CHECKBOX);
                if (!cbEl) return;
                e.stopPropagation();

                const item = cbEl.closest('.' + CLS.ITEM);
                const group = cbEl.closest('.' + CLS.GROUP);
                const checked = stateRef.checked ? { ...stateRef.checked } : {};

                if (item) {
                    // Individual item checkbox — toggle checked AND selection
                    if (razyui(item).hasClass(CLS.DISABLED)) return;
                    const val = item.dataset.value;
                    checked[val] = !checked[val];

                    if (isMultiple) {
                        const current = Array.isArray(stateRef.value) ? [...stateRef.value] : [];
                        const idx = current.indexOf(val);
                        if (checked[val] && idx < 0) current.push(val);
                        else if (!checked[val] && idx >= 0) current.splice(idx, 1);
                        setState({ value: current, checked });
                    } else {
                        // Single select — uncheck all others, select this one
                        for (const o of stateRef.options) {
                            if (o.value !== val) checked[o.value] = false;
                        }
                        setState({ value: checked[val] ? val : '', checked });
                    }
                    syncCheckboxState(self.#optionsList[0], stateRef);

                    if (typeof config.onCheckboxChange === 'function') {
                        config.onCheckboxChange.call(self, val, checked[val], checked);
                    }
                    if (typeof config.onSelect === 'function') {
                        config.onSelect.call(self, isMultiple ? stateRef.value : stateRef.value);
                    }
                    self.#emit('select', { value: isMultiple ? stateRef.value : stateRef.value });
                    self.#emit('change', { value: isMultiple ? stateRef.value : stateRef.value });
                } else if (group) {
                    // Group checkbox — toggle all children checked AND selection
                    const groupName = group.dataset.groupName;
                    const groupOpts = stateRef.options.filter(o => o.group === groupName && !o.disabled);
                    const allChecked = groupOpts.length > 0 && groupOpts.every(o => checked[o.value]);
                    const newState = !allChecked;
                    for (const o of groupOpts) {
                        checked[o.value] = newState;
                    }

                    if (isMultiple) {
                        const current = Array.isArray(stateRef.value) ? [...stateRef.value] : [];
                        for (const o of groupOpts) {
                            const idx = current.indexOf(o.value);
                            if (newState && idx < 0) current.push(o.value);
                            else if (!newState && idx >= 0) current.splice(idx, 1);
                        }
                        setState({ value: current, checked });
                    } else {
                        setState({ checked });
                    }
                    syncCheckboxState(self.#optionsList[0], stateRef);

                    if (typeof config.onCheckboxChange === 'function') {
                        config.onCheckboxChange.call(self, groupName, newState, checked);
                    }
                    if (isMultiple && typeof config.onSelect === 'function') {
                        config.onSelect.call(self, stateRef.value);
                    }
                    if (isMultiple) {
                        self.#emit('select', { value: stateRef.value });
                        self.#emit('change', { value: stateRef.value });
                    }
                }
            } : null,
            onExpandClick: (e) => {
                e.stopPropagation();
                self.#openDarkroom();
            },
        });

        // ── Autocomplete input events ──
        if (config.autocomplete && this.#acInput && this.#acInput.length) {
            const inputEl = this.#acInput[0];
            const evtOpts = { signal: this.#eventAC.signal };

            // Typing in the input → open dropdown + filter options
            inputEl.addEventListener('input', () => {
                if (!stateRef.open) {
                    setState({ open: true });
                    self.#attachOutsideClick();
                    self.#emit('open');
                }
                filterOptionItems(self.#optionsList[0], inputEl.value);
            }, evtOpts);

            // Focus → open dropdown (show all options)
            inputEl.addEventListener('focus', () => {
                if (stateRef.disabled || stateRef.readonly) return;
                if (!stateRef.open) {
                    setState({ open: true });
                    self.#attachOutsideClick();
                    self.#emit('open');
                }
            }, evtOpts);

            // Prevent container click from toggling when clicking the input
            inputEl.addEventListener('mousedown', (e) => e.stopPropagation(), evtOpts);
            inputEl.addEventListener('click', (e) => e.stopPropagation(), evtOpts);
        }

        // ── Keyboard navigation (Arrow Up/Down + Enter) ──
        {
            const keyTarget = (config.autocomplete && this.#acInput?.length)
                ? this.#acInput[0]
                : this.#container[0];
            const evtOpts = { signal: this.#eventAC.signal };

            keyTarget.addEventListener('keydown', (e) => {
                if (!stateRef.open) {
                    // Open dropdown on ArrowDown when closed
                    if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
                        e.preventDefault();
                        self.#container[0].click();
                    }
                    return;
                }

                const items = [...self.#optionsList[0].querySelectorAll(
                    '.' + CLS.ITEM + ':not(.' + CLS.DISABLED + ')',
                )].filter(el => el.offsetParent !== null); // skip filtered-out items
                if (!items.length) return;
                const active = items.findIndex(el => el.classList.contains(CLS.FOCUSED));

                if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
                    e.preventDefault();
                    const dir = e.key === 'ArrowDown' ? 1 : -1;
                    const next = active < 0 ? 0 : (active + dir + items.length) % items.length;
                    items.forEach(el => el.classList.remove(CLS.FOCUSED));
                    items[next].classList.add(CLS.FOCUSED);
                    items[next].scrollIntoView({ block: 'nearest' });
                } else if (e.key === 'Enter') {
                    if (active >= 0) {
                        e.preventDefault();
                        items[active].click();
                        items[active].classList.remove(CLS.FOCUSED);
                    }
                }
            }, evtOpts);
        }

        // ── Load initial options ──
        this.#loadOptions();
    }

    // ────────────────────────────────────────────
    // Private methods
    // ────────────────────────────────────────────

    /** Load options — remote if url provided, else from native <select>. */
    async #loadOptions() {
        const config = this.#config;
        const selectEl = this.#select[0];

        if (config.url) {
            // Show loading state
            this.#container.addClass(CLS.LOADING);
            this.#container[0].setAttribute('aria-busy', 'true');
            try {
                const data = await razyui.ajax(config.url);
                const options = normalizeRemoteData(data, config, razyui);
                this.#setState({ options });
            } catch (e) {
                // Fallback to native options
                this.#setState({ options: parseNativeOptions(selectEl) });
            } finally {
                this.#container.removeClass(CLS.LOADING);
                this.#container[0].setAttribute('aria-busy', 'false');
            }
        } else {
            this.#setState({ options: parseNativeOptions(selectEl) });
        }

        // Set initial value from native select or data-default
        const initialValue = readInitialValue(selectEl, this.#stateRef.options);
        this.#setState({ value: initialValue });
    }

    /** Attach outside-click listener to close dropdown. */
    #attachOutsideClick() {
        this.#detachOutsideClick();
        this.#outsideAC = attachOutsideClick(
            this.#container[0],
            this.#floating[0],
            () => {
                this.#setState({ open: false });
                this.#detachOutsideClick();
                this.#emit('close');
            },
            { scroll: true, resize: true, escape: true, guardMs: DEFAULTS.guardMs },
        );
    }

    /** Remove outside-click listener. */
    #detachOutsideClick() {
        this.#outsideAC?.abort();
        this.#outsideAC = null;
    }

    /** Open fullscreen darkroom overlay. */
    #openDarkroom() {
        if (this.#stateRef.disabled || this.#stateRef.readonly) return;
        if (this.#overlay) return; // prevent duplicate overlays

        // Close normal dropdown if open
        if (this.#stateRef.open) {
            this.#setState({ open: false });
            this.#detachOutsideClick();
        }

        const selectEl = this.#select[0];
        const isMultiple = selectEl.type === 'select-multiple';
        const self = this;

        const drRefs = openDarkroom(razyui, this.#stateRef, this.#config, selectEl, {
            onClose: () => self.#closeDarkroom(),
            onItemClick: (val, bodyEl) => {
                if (isMultiple) {
                    const cur = Array.isArray(self.#stateRef.value) ? [...self.#stateRef.value] : [];
                    const idx = cur.indexOf(val);
                    if (idx >= 0) cur.splice(idx, 1); else cur.push(val);
                    self.#setState({ value: cur });
                    // Sync checkboxes if checkbox mode
                    if (self.#config.checkbox) {
                        const checked = self.#stateRef.checked ? { ...self.#stateRef.checked } : {};
                        for (const o of self.#stateRef.options) {
                            checked[o.value] = cur.includes(o.value);
                        }
                        self.#setState({ checked });
                        syncCheckboxState(bodyEl, self.#stateRef);
                    }
                    syncSelectionState(bodyEl, self.#stateRef, selectEl);
                } else {
                    self.#setState({ value: val });
                    self.#closeDarkroom();
                }
                if (typeof self.#config.onSelect === 'function') {
                    self.#config.onSelect.call(self, isMultiple ? self.#stateRef.value : val);
                }
                const drEmitVal = isMultiple ? self.#stateRef.value : val;
                self.#emit('select', { value: drEmitVal });
                self.#emit('change', { value: drEmitVal });
            },
            onCheckboxClick: self.#config.checkbox ? (e, bodyEl) => {
                const cbEl = e.target.closest('.' + CLS.CHECKBOX);
                if (!cbEl) return;
                e.stopPropagation();

                const item = cbEl.closest('.' + CLS.ITEM);
                const group = cbEl.closest('.' + CLS.GROUP);
                const checked = self.#stateRef.checked ? { ...self.#stateRef.checked } : {};

                if (item) {
                    if (razyui(item).hasClass(CLS.DISABLED)) return;
                    const val = item.dataset.value;
                    checked[val] = !checked[val];

                    if (isMultiple) {
                        const cur = Array.isArray(self.#stateRef.value) ? [...self.#stateRef.value] : [];
                        const idx = cur.indexOf(val);
                        if (checked[val] && idx < 0) cur.push(val);
                        else if (!checked[val] && idx >= 0) cur.splice(idx, 1);
                        self.#setState({ value: cur, checked });
                    } else {
                        for (const o of self.#stateRef.options) {
                            if (o.value !== val) checked[o.value] = false;
                        }
                        self.#setState({ value: checked[val] ? val : '', checked });
                    }
                    syncCheckboxState(bodyEl, self.#stateRef);
                    syncSelectionState(bodyEl, self.#stateRef, selectEl);

                    if (typeof self.#config.onCheckboxChange === 'function') {
                        self.#config.onCheckboxChange.call(self, val, checked[val], checked);
                    }
                    if (typeof self.#config.onSelect === 'function') {
                        self.#config.onSelect.call(self, isMultiple ? self.#stateRef.value : self.#stateRef.value);
                    }
                    self.#emit('select', { value: isMultiple ? self.#stateRef.value : self.#stateRef.value });
                    self.#emit('change', { value: isMultiple ? self.#stateRef.value : self.#stateRef.value });
                } else if (group) {
                    const groupName = group.dataset.groupName;
                    const groupOpts = self.#stateRef.options.filter(o => o.group === groupName && !o.disabled);
                    const allChecked = groupOpts.length > 0 && groupOpts.every(o => checked[o.value]);
                    const newState = !allChecked;
                    for (const o of groupOpts) {
                        checked[o.value] = newState;
                    }

                    if (isMultiple) {
                        const cur = Array.isArray(self.#stateRef.value) ? [...self.#stateRef.value] : [];
                        for (const o of groupOpts) {
                            const idx = cur.indexOf(o.value);
                            if (newState && idx < 0) cur.push(o.value);
                            else if (!newState && idx >= 0) cur.splice(idx, 1);
                        }
                        self.#setState({ value: cur, checked });
                    } else {
                        self.#setState({ checked });
                    }
                    syncCheckboxState(bodyEl, self.#stateRef);
                    syncSelectionState(bodyEl, self.#stateRef, selectEl);

                    if (typeof self.#config.onCheckboxChange === 'function') {
                        self.#config.onCheckboxChange.call(self, groupName, newState, checked);
                    }
                    if (isMultiple && typeof self.#config.onSelect === 'function') {
                        self.#config.onSelect.call(self, self.#stateRef.value);
                    }
                    if (isMultiple) {
                        self.#emit('select', { value: self.#stateRef.value });
                        self.#emit('change', { value: self.#stateRef.value });
                    }
                }
            } : null,
        });

        this.#overlay = drRefs.overlay;
        this.#darkroomBody = drRefs.darkroomBody;
        bindDarkroomClose(this.#overlay, () => self.#closeDarkroom());
    }

    /** Close darkroom overlay. */
    #closeDarkroom() {
        closeDarkroom(this.#overlay);
        this.#overlay = null;
        this.#darkroomBody = null;
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /** 
     * Get the current value (string or array for multiple). 
     * @returns {string|string[]|null} The current value.
     */
    getValue() {
        return this.#stateRef?.value ?? null;
    }

    /** 
     * Set the current value programmatically. 
     * @param {string|string[]} value - The value to set.
     */
    setValue(value) {
        this.#setState({ value });
        // Sync darkroom panel if currently open
        if (this.#darkroomBody) {
            syncSelectionState(this.#darkroomBody, this.#stateRef, this.#select[0]);
        }
        if (typeof this.#config.onSelect === 'function') {
            this.#config.onSelect.call(this, value);
        }
        this.#emit('select', { value });
        this.#emit('change', { value });
    }

    /** 
     * Replace options list. 
     * @param {Array<{value: string, text: string, disabled?: boolean, group?: string}>} options - The new options list.
     */
    setOptions(options) {
        this.#setState({ options });
    }

    /** 
     * Open or close the dropdown. 
     * @param {boolean} open - True to open, false to close.
     */
    setOpen(open) {
        if (open && (this.#stateRef.disabled || this.#stateRef.readonly)) return;
        this.#setState({ open: !!open });
        if (open) {
            this.#attachOutsideClick();
        } else {
            this.#detachOutsideClick();
        }
        this.#emit(open ? 'open' : 'close');
    }

    open()  { this.setOpen(true); }
    close() { this.setOpen(false); }
    toggle() { this.setOpen(!this.#stateRef.open); }
    get isOpen() { return !!this.#stateRef.open; }

    /** 
     * Enable or disable the select. 
     * @param {boolean} disabled - True to disable, false to enable.
     */
    setDisabled(disabled) {
        this.#setState({ disabled: !!disabled });
        this.#select.prop('disabled', !!disabled);
        this.#container[0].setAttribute('aria-disabled', String(!!disabled));
    }

    setInvalid(invalid) {
        this.#container.toggleClass(CLS.INVALID, !!invalid);
        this.#container[0][invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { (this.#acInput?.[0] || this.#container[0])?.focus(); }
    blur()  { (this.#acInput?.[0] || this.#container[0])?.blur(); }

    clear() {
        this.setValue(this.#config.multiple ? [] : '');
        if (this.#config.checkbox) this.setChecked({});
    }

    /** 
     * Toggle readonly state. 
     * @param {boolean} readonly - True to make readonly, false otherwise.
     */
    setReadonly(readonly) {
        this.#setState({ readonly: !!readonly });
        this.#container[0].setAttribute('aria-readonly', String(!!readonly));
    }

    /**
     * Get the current checked state map.
     * @returns {Object|null} Map of value → boolean, or null if checkbox not enabled.
     */
    getChecked() {
        return this.#stateRef?.checked ?? null;
    }

    /**
     * Set checkbox states programmatically.
     * @param {Object} checked - Map of value → boolean.
     */
    setChecked(checked) {
        if (!this.#config.checkbox) return;
        this.#setState({ checked: { ...checked } });
        syncCheckboxState(this.#optionsList[0], this.#stateRef);
        if (this.#darkroomBody) {
            syncCheckboxState(this.#darkroomBody, this.#stateRef);
        }
    }

    /**
     * Return a control object with property setters (GridTable-style).
     *   ctrl.value = 'x'     → triggers state update + DOM sync
     *   ctrl.options = [...]  → replaces option list
     *   ctrl.disabled = true  → disables
     *   ctrl.readonly = true  → makes readonly
     *   ctrl.open = true      → opens dropdown
     * @returns {Object} The control object.
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.getValue(); },
            set value(v) { self.setValue(v); },
            get options() { return self.#stateRef.options; },
            set options(v) { self.setOptions(v); },
            get disabled() { return self.#stateRef.disabled; },
            set disabled(v) { self.setDisabled(v); },
            get readonly() { return self.#stateRef.readonly; },
            set readonly(v) { self.setReadonly(v); },
            get open() { return self.#stateRef.open; },
            set open(v) { self.setOpen(v); },
            get checked() { return self.getChecked(); },
            set checked(v) { self.setChecked(v); },
            get placeholder() { return self.#config.placeholder; },
            set placeholder(v) {
                self.#config.placeholder = v ?? '';
                const label = self.#container?.[0]?.querySelector?.('.combobox-label');
                if (label && !self.#stateRef.value) label.textContent = v ?? '';
            },
            get required() { return self.#select[0].required; },
            set required(v) { self.#select[0].required = !!v; self.#container[0].setAttribute('aria-required', String(!!v)); },
            destroy:           () => self.destroy(),
            setInvalid:        (v) => self.setInvalid(v),
            checkValidity:     () => self.#select[0].checkValidity(),
            reportValidity:    () => self.#select[0].reportValidity(),
            setCustomValidity: (m) => { self.#select[0].setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#container[0].getAttribute('aria-label'); },
            set label(v) { v ? self.#container[0].setAttribute('aria-label', v) : self.#container[0].removeAttribute('aria-label'); },
            get labelledby() { return self.#container[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container[0].setAttribute('aria-labelledby', v) : self.#container[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container[0].getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#container[0].setAttribute('aria-describedby', v) : self.#container[0].removeAttribute('aria-describedby'); },
            focus:  () => self.focus(),
            blur:   () => self.blur(),
            clear:  () => self.clear(),
            toggle: () => self.toggle(),
            get isOpen() { return self.isOpen; },
            get loading() { return self.#container.hasClass(CLS.LOADING); },
            get name() { return self.#select[0].name; },
            set name(v) { self.#select[0].name = v ?? ''; },
            get element() { return self.#container[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Tear down the component — restore native <select>. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#detachOutsideClick();
        this.#closeDarkroom();
        this.#eventAC?.abort();
        if (this.#floating.parent()[0]) {
            this.#floating[0].remove();
        }
        const containerEl = this.#container[0];
        if (containerEl) {
            containerEl.remove();
        }
        if (this.#select[0]) {
            this.#select.css('display', '');
        }
    }
};

export default Combobox;
