/**
 * @fileoverview Combobox view — DOM setup, effects, rendering, positioning, darkroom.
 * @module module/Combobox/view
 */

import razyui from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { CLS, SPELL, SVG, DEFAULTS, TEXT, PART } from './constants.js';
import { positionFloating as _positionFloating } from '../shared/positionFloating.js';
import { setContent } from '../shared/setContent.js';

/**
 * Build a checkbox <span> element.
 * @param {boolean} checked — initial checked state
 * @returns {HTMLSpanElement}
 */
function createCheckbox(checked) {
    const el = document.createElement('span');
    el.className = CLS.CHECKBOX;
    if (checked) el.classList.add(CLS.CHECKED);
    PART.CHECKBOX.apply(el);
    return el;
}

// ═══════════════════════════════════════
//  Filter helpers
// ═══════════════════════════════════════

/**
 * Determine whether the filter input should be shown.
 * @param {object} config   — component config
 * @param {object} stateRef — reactive state (needs .options)
 * @returns {boolean}
 */
function shouldShowFilter(config, stateRef) {
    const f = config.filter;
    if (f === true) return true;
    if (typeof f === 'number' && f > 0) return stateRef.options.length >= f;
    return false;
}

/**
 * Create a filter search input element.
 * @param {object}   razyui  — razyui core
 * @param {Function} onInput — callback(value)
 * @param {AbortSignal} [signal] — optional AbortSignal for listener cleanup
 * @returns {HTMLInputElement}
 */
function createFilterInput(razyui, onInput, signal) {
    const input = document.createElement('input');
    input.type = 'text';
    input.className = CLS.FILTER;
    input.placeholder = 'Search\u2026';
    input.autocomplete = 'off';
    PART.FILTER.apply(input);
    const opts = signal ? { signal } : undefined;
    input.addEventListener('input', () => onInput(input.value), opts);
    // Prevent click from bubbling to container (which would close/toggle)
    input.addEventListener('mousedown', e => e.stopPropagation(), opts);
    input.addEventListener('click', e => e.stopPropagation(), opts);
    return input;
}

// ═══════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════

/**
 * Build the Combobox DOM structure around the native <select>.
 *
 * @param {object} razyui   — razyui core reference
 * @param {object} config   — component config
 * @param {HTMLSelectElement} selectEl — native <select> element
 * @returns {{ container, label, floating, optionsList, expandBtn }}
 */
export function buildDOM(razyui, config, selectEl) {
    const isAC = !!config.autocomplete;

    // Container: .combobox-container > (.combobox-label | .combobox-input) + .combobox-chevron
    const container = razyui.spell(isAC ? SPELL.CONTAINER_AC : SPELL.CONTAINER, true);

    let label = null;
    let acInput = null;

    if (isAC) {
        acInput = container.find('.' + CLS.AC_INPUT);
        if (config.placeholder) acInput.setAttr({ placeholder: config.placeholder });
        PART.AC_INPUT.apply(acInput[0]);
        container.addClass(CLS.AUTOCOMPLETE);
    } else {
        ({ label } = container.collect({ label: '.' + CLS.LABEL }, 0));
        PART.LABEL.apply(label[0]);
    }

    // Apply JIT part classes to structural elements
    PART.CONTAINER.apply(container[0]);
    // Non-autocomplete containers need tabindex for keyboard navigation
    if (!isAC) container[0].setAttribute('tabindex', '0');
    const chevronEl = container.find('.' + CLS.CHEVRON)[0];
    if (chevronEl) {
        chevronEl.innerHTML = SVG.CHEVRON;
        PART.CHEVRON.apply(chevronEl);
    }

    // When rendered inside another component (e.g. GridTable), apply context class
    if (config.renderContext) {
        container.addClass('is-' + config.renderContext);
    }

    // Floating dropdown (created once, hidden by default)
    const floating = razyui.spell(SPELL.FLOATING, true);
    const { options: optionsList } = floating.collect({ options: '.' + CLS.OPTIONS }, 0);

    // Apply JIT part classes to floating structure
    PART.FLOATING.apply(floating[0]);
    PART.OPTIONS.apply(optionsList[0]);

    // Insert container after the native select, hide native
    razyui(selectEl).css('display', 'none');
    selectEl.parentNode.insertBefore(container[0], selectEl.nextSibling);

    // Display mode setup: darkroom (expand button inside container)
    let expandBtn = null;
    if (config.display === 'darkroom') {
        expandBtn = razyui.el('button', { type: 'button', className: CLS.EXPAND, title: TEXT.EXPAND_TITLE, innerHTML: SVG.EXPAND });
        PART.EXPAND.apply(expandBtn[0] || expandBtn);
        container.append(expandBtn);
    }

    return { container, label, acInput, floating, optionsList, expandBtn };
}

// ═══════════════════════════════════════
//  Reactive State Effects
// ═══════════════════════════════════════

/**
 * Wire all reactive effects for the Combobox.
 *
 * @param {Array}  stateSet — [stateRef, setState] with .effect()
 * @param {object} refs     — { container, label, floating, optionsList }
 * @param {object} config   — component config
 * @param {HTMLSelectElement} selectEl — native <select> element
 */
export function wireEffects(stateSet, refs, config, selectEl) {
    const [stateRef] = stateSet;
    const isMultiple = selectEl.type === 'select-multiple';
    const isAC = !!config.autocomplete;
    let wasOpen = false;

    // ── Effect 1: Sync label text from value + options ──
    stateSet.effect(function () {
        const state = this;
        const opts = state.options;

        // In autocomplete mode, only update the input when dropdown is closed
        // (while open, the user is typing a filter query)
        if (isAC) {
            if (!state.open && refs.acInput && refs.acInput.length) {
                const match = (state.value !== null && state.value !== '')
                    ? opts.find(o => o.value === state.value)
                    : null;
                const text = match
                    ? (typeof config.onDrawLabel === 'function' ? config.onDrawLabel(match) : match.text)
                    : '';
                refs.acInput[0].value = text;
            }
            return;
        }

        if (isMultiple) {
            const selected = Array.isArray(state.value) ? state.value : [];
            const labels = opts
                .filter(o => selected.includes(o.value))
                .map(o => {
                    if (typeof config.onDrawLabel === 'function') {
                        return config.onDrawLabel(o);
                    }
                    return o.text;
                });
            if (labels.length) {
                const joined = labels.join(', ');
                if (labels.length > 1) {
                    // Set compact text first so inline-flex containers don't grow
                    const summaryText = labels.length + TEXT.ITEMS_SELECTED;
                    refs.label.text(summaryText);
                    requestAnimationFrame(() => {
                        const el = refs.label[0];
                        if (!el) return;
                        const containerEl = el.closest('.' + CLS.CONTAINER);
                        const maxW = containerEl
                            ? containerEl.clientWidth - DEFAULTS.overflowPadding
                            : el.clientWidth;
                        // Measure joined text off-screen to avoid layout thrash
                        const measure = document.createElement('span');
                        const cs = getComputedStyle(el);
                        measure.style.cssText = 'position:absolute;visibility:hidden;white-space:nowrap;'
                            + 'font:' + cs.font + ';letter-spacing:' + cs.letterSpacing + ';';
                        measure.textContent = joined;
                        document.body.appendChild(measure);
                        const fits = measure.offsetWidth <= maxW;
                        measure.remove();
                        if (fits) {
                            el.textContent = joined;
                        }
                    });
                } else {
                    refs.label.text(joined);
                }
            } else {
                refs.label.text(state.placeholder);
            }
        } else {
            const match = opts.find(o => o.value === state.value);
            if (match) {
                const hasCustomLabel = typeof config.onDrawLabel === 'function';
                const text = hasCustomLabel
                    ? config.onDrawLabel(match)
                    : match.text;
                if (hasCustomLabel) {
                    setContent(refs.label, text);
                } else {
                    refs.label.text(text);
                }
            } else {
                refs.label.text(state.placeholder);
            }
        }

        // Sync label placeholder style
        if (refs.label.length) {
            const hasValue = isMultiple
                ? (Array.isArray(state.value) && state.value.length > 0)
                : (state.value !== null && state.value !== '');
            refs.label.toggleClass(CLS.PLACEHOLDER, !hasValue);
        }
    });

    // ── Effect 2: Sync disabled / readonly on container ──
    stateSet.effect(function () {
        if (!refs.container.length) return;
        refs.container.toggleClass(CLS.DISABLED, !!this.disabled)
                      .toggleClass(CLS.READONLY, !!this.readonly);
    });

    // ── Class-state controllers: chevron rotation on open / flipped ──
    const chevron = refs.container.length ? refs.container.find('.' + CLS.CHEVRON) : null;
    const openState = razyui(refs.container).classState(CLS.OPEN, (active) => {
        if (chevron && chevron.length) chevron.css('transform', active ? 'rotate(180deg)' : '');
    });
    const flippedState = razyui(refs.container).classState(CLS.FLIPPED, (active) => {
        if (chevron && chevron.length) chevron.css('transform', active ? 'rotate(180deg)' : '');
    });

    // ── Effect 3: Sync open state (show/hide floating + render options) ──
    stateSet.effect(function () {
        if (!refs.floating.length) return;
        const floatingEl = refs.floating[0];
        const containerEl = refs.container[0];

        if (this.open) {
            // Only rebuild option DOM when transitioning closed → open
            if (!wasOpen) {
                renderOptions(refs.optionsList[0], stateRef, selectEl, config);
                wasOpen = true;

                // In autocomplete mode, apply current input filter immediately;
                // skip the separate dropdown filter input entirely.
                if (isAC) {
                    const q = refs.acInput && refs.acInput.length ? refs.acInput[0].value : '';
                    filterOptionItems(refs.optionsList[0], q);
                } else if (shouldShowFilter(config, stateRef)) {
                    const existing = floatingEl.querySelector('.' + CLS.FILTER);
                    if (!existing) {
                        const filterInput = createFilterInput(razyui, (val) => {
                            filterOptionItems(refs.optionsList[0], val);
                        });
                        floatingEl.prepend(filterInput);
                    }
                    // Reset & focus
                    const input = floatingEl.querySelector('.' + CLS.FILTER);
                    if (input) {
                        input.value = '';
                        filterOptionItems(refs.optionsList[0], '');
                        requestAnimationFrame(() => input.focus());
                    }
                }
            } else {
                syncSelectionState(refs.optionsList[0], stateRef, selectEl);
            }

            // Append to body
            if (!floatingEl.isConnected) {
                razyui(document.body).append(floatingEl);
            }

            // Inherit data-theme from nearest themed ancestor so dark mode works
            const themed = containerEl.closest('[data-theme]');
            if (themed) {
                floatingEl.setAttribute('data-theme', themed.getAttribute('data-theme'));
            } else {
                floatingEl.removeAttribute('data-theme');
            }

            // Position floating dropdown
            positionFloating(floatingEl, containerEl, config.dropdownGap);

            openState.enable(refs.container);

            // Acquire z-index from central registry
            zIndexRegistry.acquire(floatingEl);
        } else {
            wasOpen = false;
            zIndexRegistry.release(floatingEl);
            refs.floating.css('display', 'none');
            openState.disable(refs.container);
            flippedState.disable(refs.container);
        }
    });

    // ── Effect 4: Sync native <select> value when state changes ──
    stateSet.effect(function () {
        const opts = selectEl.options;
        if (!opts) return;
        if (isMultiple) {
            const selected = Array.isArray(this.value) ? this.value : [];
            for (let i = 0; i < opts.length; i++) {
                opts[i].selected = selected.includes(opts[i].value);
            }
        } else {
            selectEl.value = this.value ?? '';
        }
    });
}

// ═══════════════════════════════════════
//  Floating Positioning
// ═══════════════════════════════════════

/**
 * Position the floating dropdown relative to the container.
 *
 * @param {HTMLElement} floatingEl   — .combobox-floating element
 * @param {HTMLElement} containerEl  — .combobox-container element
 * @param {number}      gap          — pixel gap between container and dropdown
 */
export function positionFloating(floatingEl, containerEl, gap) {
    const $container = razyui(containerEl);

    // Append to body if needed (done externally before this call)
    const { flipped } = _positionFloating(floatingEl, containerEl, {
        strategy:       'absolute',
        gap,
        flip:           true,
        viewportMargin: DEFAULTS.viewportMargin,
        width:          'min-match',
        minWidth:       DEFAULTS.minDropdownWidth,
    });

    if (flipped) {
        $container.addClass(CLS.FLIPPED);
    } else {
        $container.removeClass(CLS.FLIPPED);
    }
}

// ═══════════════════════════════════════
//  Option Rendering
// ═══════════════════════════════════════

/**
 * Render option items into a target element.
 *
 * @param {HTMLElement} listEl           — target element to populate
 * @param {object}      stateRef         — reactive state reference
 * @param {HTMLSelectElement} selectEl   — native <select> element
 * @param {object}      config           — component config
 * @param {function}   [renderCallback]  — optional custom renderer override
 */
export function renderOptions(listEl, stateRef, selectEl, config, renderCallback) {
    if (!listEl) return;
    const $list = razyui(listEl);
    $list.html('');

    const isMultiple = selectEl.type === 'select-multiple';
    const selected = isMultiple
        ? (Array.isArray(stateRef.value) ? stateRef.value : [])
        : [stateRef.value];
    const useCheckbox = !!config.checkbox;
    const checked = stateRef.checked || {};
    const groupCheckbox = useCheckbox && config.checkboxGroup !== false;

    let currentGroup = null;
    for (const opt of stateRef.options) {
        // Optgroup header
        if (opt.group && opt.group !== currentGroup) {
            currentGroup = opt.group;
            const groupEl = razyui.el('div', { className: CLS.GROUP });
            PART.GROUP.apply(groupEl[0] || groupEl);
            if (groupCheckbox) {
                // Determine group checked state from its children
                const groupOpts = stateRef.options.filter(o => o.group === currentGroup && !o.disabled);
                const allChecked = groupOpts.length > 0 && groupOpts.every(o => checked[o.value]);
                groupEl.append(createCheckbox(allChecked));
                groupEl.addClass(CLS.HAS_CHECKBOX);
                groupEl.setAttr({ 'data-group-name': currentGroup });
            }
            groupEl.append(razyui.el('span', { textContent: currentGroup }));
            $list.append(groupEl[0]);
        }

        const item = razyui.el('div', { className: CLS.ITEM, 'data-value': opt.value });
        PART.ITEM.apply(item[0] || item);

        if (opt.group) {
            item.addClass(CLS.SUB);
            item.setAttr({ 'data-group': opt.group });
        }
        if (opt.disabled) {
            item.addClass(CLS.DISABLED);
        }
        if (selected.includes(opt.value)) {
            item.addClass(CLS.SELECTED);
        }

        // Checkbox (before label)
        if (useCheckbox) {
            item.prepend(createCheckbox(!!checked[opt.value]));
            item.addClass(CLS.HAS_CHECKBOX);
        }

        // Custom rich HTML rendering via renderCallback or onRenderOption
        const renderer = renderCallback || config.onRenderOption;
        if (typeof renderer === 'function') {
            const content = razyui.el('div', { className: CLS.ITEM_CONTENT });
            setContent(content, renderer(opt));
            PART.ITEM_CONTENT.apply(content[0] || content);
            item.addClass(CLS.RICH).append(content);
        } else if (typeof config.onDrawLabel === 'function') {
            const span = razyui.el('span', { className: CLS.ITEM_TEXT });
            setContent(span, config.onDrawLabel(opt));
            PART.ITEM_TEXT.apply(span[0] || span);
            item.append(span);
        } else {
            // Default: plain text label
            const span = razyui.el('span', { className: CLS.ITEM_TEXT, textContent: opt.text });
            PART.ITEM_TEXT.apply(span[0] || span);
            item.append(span);
        }

        // Checkmark (CSS handles visibility)
        const checkEl = razyui.el('span', { className: CLS.CHECK });
        PART.CHECK.apply(checkEl[0] || checkEl);
        item.append(checkEl);

        $list.append(item[0]);
    }
}

/**
 * Update is-selected class on existing option items without rebuilding DOM.
 *
 * @param {HTMLElement} listEl         — target element containing option items
 * @param {object}      stateRef       — reactive state reference
 * @param {HTMLSelectElement} selectEl — native <select> element
 */
export function syncSelectionState(listEl, stateRef, selectEl) {
    if (!listEl) return;
    const isMultiple = selectEl.type === 'select-multiple';
    const selected = isMultiple
        ? (Array.isArray(stateRef.value) ? stateRef.value : [])
        : [stateRef.value];

    razyui(listEl).find('.' + CLS.ITEM).each(item => {
        razyui(item).toggleClass(CLS.SELECTED, selected.includes(item.dataset.value));
    });
}

/**
 * Update checkbox visual states from state.checked map.
 *
 * @param {HTMLElement} listEl   — target element containing option items
 * @param {object}      stateRef — reactive state reference
 */
export function syncCheckboxState(listEl, stateRef) {
    if (!listEl || !stateRef.checked) return;
    const checked = stateRef.checked;

    // Sync item checkboxes
    razyui(listEl).find('.' + CLS.ITEM).each(item => {
        const cb = item.querySelector('.' + CLS.CHECKBOX);
        if (cb) {
            cb.classList.toggle(CLS.CHECKED, !!checked[item.dataset.value]);
        }
    });

    // Sync group checkboxes
    razyui(listEl).find('.' + CLS.GROUP).each(group => {
        const cb = group.querySelector('.' + CLS.CHECKBOX);
        if (!cb) return;
        const groupName = group.dataset.groupName;
        const groupItems = listEl.querySelectorAll('.' + CLS.ITEM + '[data-group="' + groupName + '"]');
        let all = true;
        let count = 0;
        for (const gi of groupItems) {
            if (razyui(gi).hasClass(CLS.DISABLED)) continue;
            count++;
            if (!checked[gi.dataset.value]) { all = false; break; }
        }
        cb.classList.toggle(CLS.CHECKED, count > 0 && all);
    });
}

/**
 * Show/hide option items (and group headers) based on a search string.
 * Matches against the text content of each item, case-insensitive.
 *
 * @param {HTMLElement} listEl — .combobox-options or darkroom body element
 * @param {string}      query  — search string
 */
export function filterOptionItems(listEl, query) {
    if (!listEl) return;
    const q = (query || '').toLowerCase().trim();
    const items = listEl.querySelectorAll('.' + CLS.ITEM);
    const groups = listEl.querySelectorAll('.' + CLS.GROUP);

    // Track which groups have at least one visible item
    const visibleGroups = new Set();

    for (const item of items) {
        const text = item.textContent.toLowerCase();
        const show = !q || text.includes(q);
        item.style.display = show ? '' : 'none';
        // If item has a group, mark it visible
        if (show && item.dataset.group) {
            visibleGroups.add(item.dataset.group);
        }
    }

    // Show/hide group headers
    for (const g of groups) {
        const groupName = g.textContent;
        g.style.display = (!q || visibleGroups.has(groupName)) ? '' : 'none';
    }
}

// ═══════════════════════════════════════
//  Darkroom
// ═══════════════════════════════════════

/**
 * Open fullscreen darkroom overlay.
 *
 * @param {object}   razyui    — razyui core reference
 * @param {object}   stateRef  — reactive state reference
 * @param {object}   config    — component config
 * @param {HTMLSelectElement} selectEl — native <select> element
 * @param {object}   callbacks — { onClose, onItemClick }
 * @returns {{ overlay: HTMLElement, darkroomBody: HTMLElement }}
 */
export function openDarkroom(razyui, stateRef, config, selectEl, callbacks) {
    const dom = razyui.spell(SPELL.DARKROOM, true);
    const overlay = dom[0];

    const { title, closeBtn, body } = dom.collect({
        title: '.' + CLS.DARKROOM_HEADER + ' > span',
        closeBtn: '.' + CLS.DARKROOM_CLOSE,
        body: '.' + CLS.DARKROOM_BODY,
    }, 0);

    // Apply JIT part classes to darkroom structure
    PART.OVERLAY.apply(overlay);
    const darkroomEl = overlay.querySelector('.' + CLS.DARKROOM);
    if (darkroomEl) PART.DARKROOM.apply(darkroomEl);
    const darkroomHeaderEl = overlay.querySelector('.' + CLS.DARKROOM_HEADER);
    if (darkroomHeaderEl) PART.DARKROOM_HEADER.apply(darkroomHeaderEl);
    PART.DARKROOM_CLOSE.apply(closeBtn[0]);
    PART.DARKROOM_BODY.apply(body[0]);

    title.text(config.placeholder || TEXT.SELECT_DEFAULT);
    closeBtn.attr('type', 'button').html(TEXT.CLOSE_HTML);

    const bodyEl = body[0];
    razyui(document.body).append(overlay);

    // Inherit data-theme from nearest themed ancestor so dark mode works
    const themed = selectEl.closest('[data-theme]');
    if (themed) {
        overlay.setAttribute('data-theme', themed.getAttribute('data-theme'));
    }

    // Acquire z-index from central registry
    zIndexRegistry.acquire(overlay);

    // Render options into darkroom body (use onRenderDarkroom if provided)
    renderOptions(bodyEl, stateRef, selectEl, config,
        config.onRenderDarkroom || config.onRenderOption);

    // Insert filter input into darkroom if enabled
    if (shouldShowFilter(config, stateRef)) {
        const darkroom = overlay.querySelector('.' + CLS.DARKROOM_HEADER);
        if (darkroom) {
            const filterInput = createFilterInput(razyui, (val) => {
                filterOptionItems(bodyEl, val);
            });
            darkroom.after(filterInput);
            requestAnimationFrame(() => filterInput.focus());
        }
    }

    // ── Event wiring ──
    closeBtn.on('click', () => callbacks.onClose());
    body.on('click', (e) => {
        // Checkbox clicks handled separately
        if (e.target.closest('.' + CLS.CHECKBOX)) {
            if (typeof callbacks.onCheckboxClick === 'function') {
                callbacks.onCheckboxClick(e, bodyEl);
            }
            return;
        }
        const item = e.target.closest('.' + CLS.ITEM);
        if (!item || razyui(item).hasClass(CLS.DISABLED)) return;
        callbacks.onItemClick(item.dataset.value, bodyEl);
    });

    // Prevent body scroll
    razyui(document.body).css('overflow', 'hidden');

    return { overlay, darkroomBody: bodyEl };
}

/**
 * Close darkroom overlay and restore body scroll.
 *
 * @param {HTMLElement|null} overlay — darkroom overlay element
 */
export function closeDarkroom(overlay) {
    if (overlay) {
        zIndexRegistry.release(overlay);
        overlay.remove();
    }
    razyui(document.body).css('overflow', '');
}
