/**
 * @fileoverview Combobox helpers — pure utility functions.
 * @module module/Combobox/helpers
 */

/**
 * Parse options from a native <select> element's children.
 *
 * @param {HTMLSelectElement} selectEl — native <select> element
 * @returns {Array<{value:string, text:string, disabled:boolean, group:string|null}>}
 */
export function parseNativeOptions(selectEl) {
    const options = [];
    for (const child of selectEl.children) {
        if (child.tagName === 'OPTGROUP') {
            const group = child.label || '';
            for (const opt of child.children) {
                options.push({
                    value: opt.value,
                    text: opt.textContent,
                    disabled: opt.disabled,
                    group: group,
                });
            }
        } else if (child.tagName === 'OPTION') {
            options.push({
                value: child.value,
                text: child.textContent,
                disabled: child.disabled,
                group: null,
            });
        }
    }
    return options;
}

/**
 * Transform remote data into the internal options format.
 *
 * @param {object|Array} data   — raw response data
 * @param {object}       config — component config
 * @param {object}       razyui — razyui core reference
 * @returns {Array<{value:string, text:string, disabled:boolean, group:string|null, data:*}>}
 */
export function normalizeRemoteData(data, config, razyui) {
    let options = [];
    if (config.isKeyValuePair && razyui.isPO(data)) {
        Object.keys(data).forEach(key => {
            options.push({ value: key, text: data[key], disabled: false, group: null });
        });
    } else if (Array.isArray(data)) {
        options = data.map(item => ({
            value: String(item.value ?? item.id ?? ''),
            text: String(item.text ?? item.label ?? item.name ?? ''),
            disabled: !!item.disabled,
            group: item.group || null,
            data: item.data || null,
        }));
    }
    return options;
}

/**
 * Read the initial value from a native <select> or its data-default attribute.
 *
 * @param {HTMLSelectElement} selectEl     — native <select> element
 * @param {Array}             stateOptions — current options array from state
 * @returns {string|string[]|null}
 */
export function readInitialValue(selectEl, stateOptions) {
    const defaultVal = selectEl.dataset.default;
    const isMultiple = selectEl.type === 'select-multiple';

    if (defaultVal) {
        return isMultiple
            ? defaultVal.split(',').map(v => v.trim())
            : defaultVal;
    }

    if (isMultiple) {
        const selected = [];
        for (const opt of selectEl.selectedOptions) {
            selected.push(opt.value);
        }
        return selected;
    }

    // Default to first non-disabled option if nothing selected
    const first = stateOptions.find(o => !o.disabled);
    return selectEl.value || (first ? first.value : null);
}
